// frontend/src/App.js
import React, { useState, useEffect } from 'react';
import BookingForm from './components/BookingForm/BookingForm';
import OwnerBookings from './components/OwnerBookings/OwnerBookings';

function App() {
  const [bookings, setBookings] = useState([]);

  // загрузка всех бронирований с backend
  const fetchBookings = async () => {
    try {
      const res = await fetch('http://localhost:5000/bookings');
      const data = await res.json();
      setBookings(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchBookings(); // загрузка при старте
  }, []);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif', background: '#f5f5f5', minHeight: '100vh' }}>
      {/* Форма бронирования */}
      <BookingForm onBookingSuccess={fetchBookings} />

      <hr style={{ margin: '40px 0' }} />

      {/* Таблица для хозяина */}
      <OwnerBookings bookings={bookings} />
    </div>
  );
}

export default App;
